async (params, browser) => {
  // Open page
  await browser.open(`${params.master_url}`)

  // Wait for content
  await browser.waitForSelector('h1, [class*="title"], .profile', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim()||''; const artist = document.querySelector('h1 a')?.textContent?.trim()||''; const year = document.querySelector('[class*="year"], .profile .content')?.textContent?.trim()||''; const tracks = Array.from(document.querySelectorAll('.tracklist_track, tr[class*="track"]')).map(tr => ({ position: tr.querySelector('.tracklist_track_pos')?.textContent?.trim()||'', title: tr.querySelector('.tracklist_track_title a')?.textContent?.trim()||'', duration: tr.querySelector('.tracklist_track_duration')?.textContent?.trim()||'' })).filter(t=>t.title); const versions = Array.from(document.querySelectorAll('table.versions tbody tr')).slice(0,20).map(row => ({ title: row.querySelector('a')?.textContent?.trim()||'', format: row.querySelector('td:nth-child(3)')?.textContent?.trim()||'', country: row.querySelector('td:nth-child(4)')?.textContent?.trim()||'' })); return { title, artist, year, tracklist: tracks, versions, url: window.location.href }`)

  return page_data
}
